import { readFile } from "node:fs/promises";
import path from "node:path";
import { fileURLToPath } from "node:url";

const root = path.resolve(path.dirname(fileURLToPath(import.meta.url)), "..");

const checks = [
  {
    file: "lib/api-client-react/src/generated/api.schemas.ts",
    label: "Generated client schemas",
    patterns: [
      "Generated by orval",
      "export interface",
    ],
  },
  {
    file: "lib/api-client-react/src/generated/api.ts",
    label: "Generated client API",
    patterns: [
      "Generated by orval",
      "from './api.schemas';",
      "customFetch",
    ],
  },
  {
    file: "lib/api-zod/src/index.ts",
    label: "Zod index export",
    patterns: [
      "export * from './generated/api';",
    ],
  },
];

const failures = [];

for (const check of checks) {
  const filePath = path.resolve(root, check.file);
  let contents;
  try {
    contents = await readFile(filePath, "utf8");
  } catch (error) {
    failures.push(`${check.label}: could not read ${check.file} (${error.message})`);
    continue;
  }

  for (const pattern of check.patterns) {
    if (!contents.includes(pattern)) {
      failures.push(`${check.label}: missing "${pattern}" in ${check.file}`);
    }
  }
}

if (failures.length > 0) {
  console.error("Generated contract verification failed:");
  for (const failure of failures) {
    console.error(`- ${failure}`);
  }
  process.exit(1);
}

console.log("Generated contract verification passed.");
